import React, { useEffect, useState } from "react";
import axios from "axios";
import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import "../index.css";

const API_BASE = "http://localhost:5000/api/products";

const blankForm = {
  name: "",
  description: "",
  category: "Earphone",
  price: "",
  offerPrice: "",
  image: ""
};

function SellerDashboard() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState(blankForm);
  const [editingProduct, setEditingProduct] = useState(null);

  // Remember last tab across refresh
  const savedTab = localStorage.getItem("activePage") || "list";
  const [activePage, setActivePage] = useState(savedTab);

  useEffect(() => {
    localStorage.setItem("activePage", activePage);
  }, [activePage]);

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const res = await axios.get(API_BASE);
      setProducts(res.data);
    } catch (err) {
      console.error("Fetch products error:", err);
      toast.error("❌ Failed to load products");
    }
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingProduct) {
        const res = await axios.put('${API_BASE}/${editingProduct._id}, form');
        setProducts((prev) =>
          prev.map((p) => (p._id === res.data._id ? res.data : p))
        );
        toast.info("✏ Product updated!");
      } else {
        const res = await axios.post(API_BASE, form);
        setProducts((prev) => [res.data, ...prev]);
        toast.success("✅ Product added!");
      }
      setForm(blankForm);
      setEditingProduct(null);
      setActivePage("list");
    } catch (err) {
      console.error("Save product error:", err);
      toast.error("❌ Failed to save product");
    }
  };

  const handleEdit = (product) => {
    setEditingProduct(product);
    setForm(product);
    setActivePage("add");
  };

  const handleCancelEdit = () => {
    setEditingProduct(null);
    setForm(blankForm);
  };

  const handleDelete = async (id) => {
    const confirmDelete = window.confirm("Delete this product?");
    if (!confirmDelete) return;
    try {
      await axios.delete('${API_BASE}/${id}');
      setProducts((prev) => prev.filter((p) => p._id !== id));
      toast.warn("🗑 Product deleted");
    } catch (err) {
      console.error("Delete error:", err);
      toast.error("❌ Failed to delete product");
    }
  };

  return (
    <div className="seller-dashboard">
      {/* Sidebar */}
      <aside className="sidebar">
        <h1 className="logo">Seller Panel</h1>
        <nav>
          <ul>
            <li
              className={activePage === "add" ? "active" : ""}
              onClick={() => {
                setActivePage("add");
                setEditingProduct(null);
                setForm(blankForm);
              }}
            >
              ➕ Add Product
            </li>
            <li
              className={activePage === "list" ? "active" : ""}
              onClick={() => setActivePage("list")}
            >
              📦 Product List
            </li>
            <li onClick={() => toast.info("🕒 Orders coming soon!")}>
              📝 Orders
            </li>
          </ul>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        {activePage === "add" && (
          <form onSubmit={handleSubmit} className="product-form">
            <h3>{editingProduct ? "✏ Edit Product" : "➕ Add Product"}</h3>

            <input
              type="text"
              name="name"
              placeholder="Product Name"
              value={form.name}
              onChange={handleChange}
              required
            />

            <textarea
              name="description"
              placeholder="Description"
              value={form.description}
              onChange={handleChange}
            />

            <select
              name="category"
              value={form.category}
              onChange={handleChange}
            >
              <option>Earphone</option>
              <option>Smartphone</option>
              <option>Laptop</option>
              <option>Smartwatch</option>
              <option>Other</option>
            </select>

            <input
              type="number"
              name="price"
              placeholder="Price"
              value={form.price}
              onChange={handleChange}
              required
            />

            <input
              type="number"
              name="offerPrice"
              placeholder="Offer Price"
              value={form.offerPrice}
              onChange={handleChange}
            />

            <input
              type="text"
              name="image"
              placeholder="Image URL"
              value={form.image}
              onChange={handleChange}
              required
            />

            {form.image && <img src={form.image} alt="preview" width="120" />}

            <div className="form-actions">
              <button type="submit">
                {editingProduct ? "Update" : "Add"}
              </button>
              {editingProduct && (
                <button type="button" onClick={handleCancelEdit}>
                  Cancel
                </button>
              )}
            </div>
          </form>
        )}

        {activePage === "list" && (
          <>
            <h3>📦 Your Products</h3>
            <ul className="product-list">
              {products.map((p) => (
                <li key={p._id} className="product-item">
                  <img src={p.image} alt={p.name} />
                  <div>
                    <h4>{p.name}</h4>
                    <p>
                      ₹{p.price}{" "}
                      {'p.offerPrice && (Offer: ₹${p.offerPrice})'}
                    </p>
                    <small>{p.category}</small>
                  </div>
                  <div className="actions">
                    <button onClick={() => handleEdit(p)}>✏ Edit</button>
                    <button onClick={() => handleDelete(p._id)}>🗑 Delete</button>
                  </div>
                </li>
              ))}
            </ul>
          </>
        )}
      </main>

      {/* Toast container for notifications */}
      <ToastContainer position="top-center" autoClose={2000} />
    </div>
  );
}

export default SellerDashboard;
